--
-- Estructura de tabla para la tabla `viaje`
--

CREATE TABLE `viaje` (
  `id_viaje` int(11) NOT NULL,
  `placa` varchar(15) DEFAULT NULL,
  `id_ruta` int(11) DEFAULT NULL,
  `doc_us` bigint(20) UNSIGNED DEFAULT NULL,
  `fecha` datetime DEFAULT NULL,
  `fecha_asignacion` datetime DEFAULT NULL,
  `id_estado` tinyint(3) UNSIGNED DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

--
-- Volcado de datos para la tabla `viaje`
--


--
-- Disparadores `viaje`
--
DELIMITER $$
CREATE TRIGGER `after_viaje_insert` AFTER INSERT ON `viaje` FOR EACH ROW BEGIN
                DECLARE v_nit BIGINT;
                
                -- Obtener el NIT de la empresa dueña del bus
                SELECT NIT INTO v_nit FROM bus WHERE placa = NEW.placa LIMIT 1;
                
                -- Insertar en la tabla asignacion como historial
                    id_tipo_asignacion,
                    placa,
                    doc_usuario,
                    id_ruta,
                    fecha_inicio,
                    id_estado,
                    Nit
                ) VALUES (
                    4, 
                    NEW.placa, 
                    NEW.doc_us, 
                    NEW.id_ruta, 
                    DATE(NEW.fecha), 
                    NEW.id_estado, 
                    v_nit
                );
            END
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `after_viaje_update` AFTER UPDATE ON `viaje` FOR EACH ROW BEGIN
                -- Actualizar el estado en el historial si cambia en el viaje activo
                -- Esto permite saber si un viaje fue cancelado o terminado
                UPDATE asignacion 
                SET id_estado = NEW.id_estado,
                    id_ruta = NEW.id_ruta,
                    doc_usuario = NEW.doc_us
                WHERE placa = NEW.placa 
                  AND id_tipo_asignacion = 4 
                  AND DATE(fecha_inicio) = DATE(NEW.fecha);
            END
$$
DELIMITER ;

